UPDATE challenges SET test_suite = '[{"file_path": ".kodwai/test-runner.js", "runner": "node", "command": "node .kodwai/test-runner.js", "content": "const http = require(\"http\");\n\nconst PORT = process.env.PORT || 4567;\nlet passed = 0;\nlet failed = 0;\n\nasync function request(method, path, body) {\n  return new Promise((resolve, reject) => {\n    const options = { hostname: \"localhost\", port: PORT, path, method, headers: { \"Content-Type\": \"application/json\" } };\n    const req = http.request(options, (res) => {\n      let data = \"\";\n      res.on(\"data\", (chunk) => data += chunk);\n      res.on(\"end\", () => {\n        try { resolve({ status: res.statusCode, body: JSON.parse(data) }); }\n        catch { resolve({ status: res.statusCode, body: data }); }\n      });\n    });\n    req.on(\"error\", reject);\n    if (body) req.write(JSON.stringify(body));\n    req.end();\n  });\n}\n\nfunction assert(condition, msg) {\n  if (condition) { passed++; }\n  else { failed++; console.log(\"  FAIL: \" + msg); }\n}\n\nasync function run() {\n  // Start the server\n  const server = require(\"child_process\").spawn(\"node\", [\"server.js\"], { env: { ...process.env, PORT: String(PORT) }, stdio: \"pipe\" });\n  await new Promise(r => setTimeout(r, 1500));\n\n  try {\n    // POST /todos\n    let res = await request(\"POST\", \"/todos\", { title: \"Buy milk\" });\n    assert(res.status === 201, \"POST returns 201\");\n    assert(res.body && res.body.title === \"Buy milk\", \"POST returns todo with title\");\n    assert(res.body && res.body.completed === false, \"POST defaults completed to false\");\n    const id1 = res.body && res.body.id;\n\n    // POST validation\n    res = await request(\"POST\", \"/todos\", {});\n    assert(res.status === 400, \"POST without title returns 400\");\n\n    // POST second todo\n    res = await request(\"POST\", \"/todos\", { title: \"Walk dog\" });\n    assert(res.status === 201, \"POST second todo returns 201\");\n\n    // GET /todos\n    res = await request(\"GET\", \"/todos\");\n    assert(res.status === 200, \"GET /todos returns 200\");\n    const todos = Array.isArray(res.body) ? res.body : (res.body && res.body.data) || [];\n    assert(todos.length >= 2, \"GET /todos returns at least 2 todos\");\n\n    // GET /todos/:id\n    res = await request(\"GET\", \"/todos/\" + id1);\n    assert(res.status === 200, \"GET /todos/:id returns 200\");\n    assert(res.body && res.body.title === \"Buy milk\", \"GET /todos/:id returns correct todo\");\n\n    // GET /todos/:id not found\n    res = await request(\"GET\", \"/todos/nonexistent999\");\n    assert(res.status === 404, \"GET missing todo returns 404\");\n\n    // PUT /todos/:id\n    res = await request(\"PUT\", \"/todos/\" + id1, { title: \"Buy oat milk\", completed: true });\n    assert(res.status === 200, \"PUT returns 200\");\n    assert(res.body && res.body.completed === true, \"PUT updates completed\");\n\n    // PUT not found\n    res = await request(\"PUT\", \"/todos/nonexistent999\", { title: \"Nope\" });\n    assert(res.status === 404, \"PUT missing todo returns 404\");\n\n    // DELETE /todos/:id\n    res = await request(\"DELETE\", \"/todos/\" + id1);\n    assert(res.status === 200 || res.status === 204, \"DELETE returns 200 or 204\");\n    res = await request(\"GET\", \"/todos/\" + id1);\n    assert(res.status === 404, \"Deleted todo is gone\");\n\n    // DELETE not found\n    res = await request(\"DELETE\", \"/todos/nonexistent999\");\n    assert(res.status === 404, \"DELETE missing returns 404\");\n\n    console.log(passed + \" passed, \" + failed + \" failed out of \" + (passed + failed));\n  } finally {\n    server.kill();\n  }\n  process.exit(failed > 0 ? 1 : 0);\n}\n\nrun().catch(e => { console.error(e); process.exit(1); });\n"}]'
WHERE slug = 'build-rest-api';

