UPDATE challenges SET test_suite = '[{"file_path": ".kodwai/test-runner.js", "runner": "node", "command": "node .kodwai/test-runner.js", "content": "const { execSync } = require(\"child_process\");\nlet passed = 0;\nlet failed = 0;\n\nfunction check(condition, msg) {\n  if (condition) { passed++; } else { failed++; console.log(\"FAIL: \" + msg); }\n}\n\ntry {\n  // Check cli.js exists\n  const fs = require(\"fs\");\n  check(fs.existsSync(\"cli.js\"), \"cli.js exists\");\n\n  // Create test CSV\n  fs.writeFileSync(\"test-data.csv\", \"name,department,salary,start_date\\nAlice,Engineering,120000,2025-01-15\\nBob,Marketing,95000,2024-06-01\\nCharlie,Engineering,130000,2026-01-10\\nDiana,Marketing,105000,2025-08-20\\n\");\n\n  // Run CLI\n  const output = execSync(\"node cli.js test-data.csv\", { encoding: \"utf-8\", timeout: 10000 });\n  check(output.length > 0, \"CLI produces output\");\n  check(output.includes(\"Engineering\"), \"Output includes Engineering dept\");\n  check(output.includes(\"Marketing\"), \"Output includes Marketing dept\");\n\n  // JSON format\n  const jsonOut = execSync(\"node cli.js test-data.csv --format json\", { encoding: \"utf-8\", timeout: 10000 });\n  const parsed = JSON.parse(jsonOut);\n  check(typeof parsed === \"object\", \"JSON output is valid\");\n\n  // Error handling\n  try {\n    execSync(\"node cli.js nonexistent.csv\", { encoding: \"utf-8\", timeout: 5000, stdio: \"pipe\" });\n    check(false, \"Should error on missing file\");\n  } catch {\n    check(true, \"Errors on missing file\");\n  }\n\n  console.log(passed + \" passed, \" + failed + \" failed out of \" + (passed + failed));\n  process.exit(failed > 0 ? 1 : 0);\n} catch (e) {\n  console.error(e.message);\n  console.log(passed + \" passed, \" + (failed + 1) + \" failed out of \" + (passed + failed + 1));\n  process.exit(1);\n}\n"}]'
WHERE slug = 'cli-file-processing';

UPDATE challenges SET test_suite = '[{"file_path": ".kodwai/test-runner.js", "runner": "node", "command": "node .kodwai/test-runner.js", "content": "// Schema design is evaluated by AI analysis of the SQL files\n// Basic check: verify SQL files exist and contain CREATE TABLE statements\nconst fs = require(\"fs\");\nconst path = require(\"path\");\nlet passed = 0;\nlet failed = 0;\n\nfunction check(condition, msg) {\n  if (condition) { passed++; } else { failed++; console.log(\"FAIL: \" + msg); }\n}\n\n// Find SQL files\nconst files = fs.readdirSync(\".\").filter(f => f.endsWith(\".sql\"));\ncheck(files.length > 0, \"At least one .sql file exists\");\n\nlet allSql = \"\";\nfor (const f of files) { allSql += fs.readFileSync(f, \"utf-8\"); }\n\ncheck(allSql.toLowerCase().includes(\"create table\"), \"SQL contains CREATE TABLE\");\ncheck(allSql.toLowerCase().includes(\"references\") || allSql.toLowerCase().includes(\"foreign key\"), \"SQL has foreign keys\");\ncheck(allSql.toLowerCase().includes(\"primary key\"), \"SQL has primary keys\");\ncheck((allSql.match(/create table/gi) || []).length >= 4, \"At least 4 tables defined\");\n\n// Check for README\ncheck(fs.existsSync(\"README.md\") || fs.existsSync(\"readme.md\"), \"README exists\");\n\nconsole.log(passed + \" passed, \" + failed + \" failed out of \" + (passed + failed));\nprocess.exit(failed > 0 ? 1 : 0);\n"}]'
WHERE slug = 'database-schema-design';

UPDATE challenges SET test_suite = '[{"file_path": ".kodwai/test-runner.js", "runner": "node", "command": "node .kodwai/test-runner.js", "content": "// Test the rate limiter implementation\nlet passed = 0;\nlet failed = 0;\n\nfunction check(condition, msg) {\n  if (condition) { passed++; } else { failed++; console.log(\"FAIL: \" + msg); }\n}\n\ntry {\n  // Try to require the rate limiter\n  let RateLimiter;\n  try {\n    const mod = require(\"./rate-limiter\") || require(\"./rateLimiter\") || require(\"./index\");\n    RateLimiter = mod.RateLimiter || mod.default || mod;\n  } catch {\n    try { RateLimiter = require(\"./index\").RateLimiter || require(\"./index\"); } catch { }\n  }\n\n  check(typeof RateLimiter === \"function\", \"RateLimiter is a constructor/function\");\n\n  if (typeof RateLimiter === \"function\") {\n    const limiter = new RateLimiter(3, 5000);\n\n    // Should allow first 3 requests\n    check(limiter.isAllowed(\"user1\") === true, \"1st request allowed\");\n    check(limiter.isAllowed(\"user1\") === true, \"2nd request allowed\");\n    check(limiter.isAllowed(\"user1\") === true, \"3rd request allowed\");\n\n    // 4th should be denied\n    check(limiter.isAllowed(\"user1\") === false, \"4th request denied\");\n\n    // Different client should work\n    check(limiter.isAllowed(\"user2\") === true, \"Different client allowed\");\n\n    // Check remaining\n    if (typeof limiter.getRemainingRequests === \"function\") {\n      check(limiter.getRemainingRequests(\"user1\") === 0, \"user1 has 0 remaining\");\n      check(limiter.getRemainingRequests(\"user2\") === 2, \"user2 has 2 remaining\");\n    }\n\n    // Check reset time\n    if (typeof limiter.getResetTime === \"function\") {\n      const resetTime = limiter.getResetTime(\"user1\");\n      check(typeof resetTime === \"number\" && resetTime > 0, \"Reset time is positive number\");\n    }\n  }\n\n  console.log(passed + \" passed, \" + failed + \" failed out of \" + (passed + failed));\n  process.exit(failed > 0 ? 1 : 0);\n} catch (e) {\n  console.error(e.message);\n  console.log(passed + \" passed, \" + (failed + 1) + \" failed out of \" + (passed + failed + 1));\n  process.exit(1);\n}\n"}]'
WHERE slug = 'algorithm-rate-limiter';

UPDATE challenges SET test_suite = '[{"file_path": ".kodwai/test-runner.js", "runner": "node", "command": "node .kodwai/test-runner.js", "content": "// Chat app test: verify server starts and accepts WebSocket connections\nconst http = require(\"http\");\nlet passed = 0;\nlet failed = 0;\n\nfunction check(condition, msg) {\n  if (condition) { passed++; } else { failed++; console.log(\"FAIL: \" + msg); }\n}\n\nconst fs = require(\"fs\");\n\n// Check required files exist\ncheck(fs.existsSync(\"server.js\") || fs.existsSync(\"index.js\"), \"Server file exists\");\ncheck(fs.existsSync(\"index.html\") || fs.existsSync(\"public/index.html\") || fs.existsSync(\"client.html\"), \"Client HTML exists\");\n\n// Check server code has WebSocket\nconst serverFile = fs.existsSync(\"server.js\") ? \"server.js\" : \"index.js\";\nconst serverCode = fs.readFileSync(serverFile, \"utf-8\");\ncheck(serverCode.toLowerCase().includes(\"websocket\") || serverCode.includes(\"ws\"), \"Server uses WebSocket\");\ncheck(serverCode.includes(\"room\") || serverCode.includes(\"channel\"), \"Server has room support\");\ncheck(serverCode.includes(\"message\") || serverCode.includes(\"broadcast\"), \"Server handles messages\");\n\nconsole.log(passed + \" passed, \" + failed + \" failed out of \" + (passed + failed));\nprocess.exit(failed > 0 ? 1 : 0);\n"}]'
WHERE slug = 'fullstack-realtime-chat';

